export const meta = {
  name: 'first-tdd-design',
  description: 'Design the first TDD cycle for the claims adjudicator: System Architect locks the unit-under-test contract + minimal toolchain, Senior SDET authors the first failing test, adversarial reviewer reconciles doc conflicts and gives go/no-go. Proposal only — no files written.',
  phases: [
    { title: 'Design', detail: 'Architect locks contract+toolchain, then SDET authors the first failing test against it' },
    { title: 'Verify', detail: 'Adversarial reviewer reconciles conflicts vs locked rules; go/no-go' },
  ],
}

const REPO = '/Users/raunaksingh/Documents/realfast/insurance'

const READ = `
Read these files FIRST — they are the locked source of truth; do NOT contradict them:
- ${REPO}/AGENTS.md            (hard rules, locked stack, anti-patterns, commit contract)
- ${REPO}/PRD.md               (locked scope, 4 endpoints, CoverageRule shape, integer-cents rule)
- ${REPO}/TRACK.md             (decisions #1-#23, current focus, the "Next: cycle 1" notes)
- ${REPO}/docs/adjudication-plan.md  (the PURE adjudicateLine contract, the 36-cycle TDD build order, the worked numeric example)
- ${REPO}/docs/domain-model.md (entity TS types, state machines, ReasonCode set)
- ${REPO}/.claude/skills/tdd-discipline/SKILL.md  (test-first contract, BDD naming, AAA + builders, MUST/MUST-NOT, commit prefixes)
- ${REPO}/.claude/skills/insurance-domain/SKILL.md (ReasonCode enum, canonical adjudication order, edge cases)
- ${REPO}/.claude/commands/tdd-cycle.md            (the red-green-refactor command; note its NO_COVERAGE example)
- the scaffold under ${REPO}/app/src/domain/  (ALL are empty one-line placeholders today; nothing is implemented)

HARD CONSTRAINTS:
- PROPOSAL ONLY. Do NOT create, write, edit, or commit any file. Output your analysis only.
- Locked stack: TypeScript (strict) + Node 22 + vitest + biome + pnpm. The first cycle is a PURE function (no DB, no fastify, no SQLite, no drizzle) — tests 1-25 in the build order are pure.
- Money is ALWAYS integer cents. Never floats.
- Do not expand scope. One behavior for the first cycle.

KNOWN CONFLICTS you must explicitly resolve (the repo's own docs disagree):
1. WHICH BEHAVIOR IS CYCLE 1?
   - TRACK.md "Current focus" + "Notes for next agent" + the last 3 session-log "Next" entries all say cycle 1 = "no rule -> NO_COVERAGE".
   - docs/adjudication-plan.md "TDD build order" lists cycle 1 = "full_coverage line -> member 0, plan = billed (simplest happy path)" and cycle 2 = "no rule -> NO_COVERAGE".
   - .claude/commands/tdd-cycle.md uses "denies a line item with no coverage rule" (NO_COVERAGE) as its worked example.
2. NAMING CONVENTION / SIGNATURE for the pure core:
   - adjudication-plan.md AdjudicateResult uses snake_case fields (payable_cents, member_responsibility_cents, reasons[]) and the signature adjudicateLine(input: AdjudicateInput) with { line, policy, rule, serviceDate, acc, alreadyAdjudicatedFingerprint }.
   - tdd-discipline/SKILL.md example uses camelCase (payableCents, memberResponsibilityCents, reasonCode) and a different signature adjudicate({ policy, rule, accumulator, line }).
   - domain-model.md entity TS types use camelCase (memberId, serviceCode, billedCents).
   You must lock ONE convention for the actual code (the first test pins these names forever).
`

// ---------- schemas ----------
const ARCH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    contract_to_pin: {
      type: 'object',
      additionalProperties: false,
      properties: {
        function_signature: { type: 'string', description: 'Exact TS signature the first test will import and call' },
        input_shape: { type: 'string', description: 'TS type of the input the test constructs' },
        result_shape: { type: 'string', description: 'TS type of the result the test asserts on' },
        naming_convention: { type: 'string', enum: ['camelCase', 'snake_case'], description: 'The ONE convention locked for code' },
        naming_rationale: { type: 'string' },
        conflicts_resolved: { type: 'array', items: { type: 'string' } },
      },
      required: ['function_signature', 'input_shape', 'result_shape', 'naming_convention', 'naming_rationale', 'conflicts_resolved'],
    },
    toolchain_bootstrap: {
      type: 'object',
      additionalProperties: false,
      properties: {
        files: {
          type: 'array',
          items: {
            type: 'object',
            additionalProperties: false,
            properties: { path: { type: 'string' }, purpose: { type: 'string' }, key_contents: { type: 'string' } },
            required: ['path', 'purpose', 'key_contents'],
          },
        },
        runtime_deps: { type: 'array', items: { type: 'string' } },
        dev_deps: { type: 'array', items: { type: 'string' } },
        scripts: { type: 'array', items: { type: 'string' } },
        gitignore_additions: { type: 'array', items: { type: 'string' } },
        notes: { type: 'string', description: 'What NOT to add yet (fastify/sqlite/drizzle) and why' },
      },
      required: ['files', 'runtime_deps', 'dev_deps', 'scripts', 'gitignore_additions', 'notes'],
    },
    cycle1_recommendation: {
      type: 'object',
      additionalProperties: false,
      properties: { behavior: { type: 'string' }, rationale: { type: 'string' } },
      required: ['behavior', 'rationale'],
    },
    risks: { type: 'array', items: { type: 'string' } },
  },
  required: ['contract_to_pin', 'toolchain_bootstrap', 'cycle1_recommendation', 'risks'],
}

const SDET_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    first_test: {
      type: 'object',
      additionalProperties: false,
      properties: {
        behavior_name: { type: 'string', description: 'BDD-style it() name' },
        file_path: { type: 'string' },
        full_test_code: { type: 'string', description: 'Complete, runnable test file content' },
        asserts: { type: 'array', items: { type: 'string' }, description: 'Each domain assertion made' },
        red_reason: { type: 'string', description: 'The exact reason it fails BEFORE implementation (the right reason)' },
      },
      required: ['behavior_name', 'file_path', 'full_test_code', 'asserts', 'red_reason'],
    },
    builders: {
      type: 'object',
      additionalProperties: false,
      properties: {
        file_path: { type: 'string' },
        api: { type: 'array', items: { type: 'string' } },
        full_code: { type: 'string', description: 'Complete builders file content' },
      },
      required: ['file_path', 'api', 'full_code'],
    },
    green_minimum: { type: 'string', description: 'The minimum implementation sketch that turns it green (NOT to be written now, just described)' },
    commit_sequence: { type: 'array', items: { type: 'string' } },
    cycle1_recommendation: {
      type: 'object',
      additionalProperties: false,
      properties: { behavior: { type: 'string' }, rationale: { type: 'string' } },
      required: ['behavior', 'rationale'],
    },
    test_smells_avoided: { type: 'array', items: { type: 'string' } },
  },
  required: ['first_test', 'builders', 'green_minimum', 'commit_sequence', 'cycle1_recommendation', 'test_smells_avoided'],
}

const VERDICT_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    go: { type: 'boolean' },
    final_cycle1_pick: { type: 'string' },
    final_naming_convention: { type: 'string' },
    conflicts: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: { issue: { type: 'string' }, resolution: { type: 'string' } },
        required: ['issue', 'resolution'],
      },
    },
    blocking_issues: { type: 'array', items: { type: 'string' } },
    rule_violations_found: { type: 'array', items: { type: 'string' }, description: 'Any breach of AGENTS.md hard rules / tdd-discipline in the proposal' },
    adjustments: { type: 'array', items: { type: 'string' } },
    confidence: { type: 'string' },
  },
  required: ['go', 'final_cycle1_pick', 'final_naming_convention', 'conflicts', 'blocking_issues', 'rule_violations_found', 'adjustments', 'confidence'],
}

// ---------- Phase 1: Design ----------
phase('Design')

const arch = await agent(
  `You are the SYSTEM / SOLUTION ARCHITECT for this claims-adjudication take-home.
${READ}

YOUR JOB:
1. Lock the unit-under-test CONTRACT for the very first PURE adjudication cycle — the exact function signature, input shape, and result shape the first test will import and assert on. RESOLVE the snake_case vs camelCase conflict and pick ONE convention for the code (state why). The first test pins these names, so be decisive.
2. Specify the MINIMAL toolchain bootstrap that makes "pnpm test" runnable so the first test can fail for the RIGHT reason (behavior missing), not "no test runner". Locked stack only: TS strict, Node 22, vitest, biome, pnpm. Pure function only — do NOT add fastify/better-sqlite3/drizzle yet (explain why they wait). Give exact files (package.json with precise deps + scripts, tsconfig.json with strict settings, vitest.config.ts) and their key contents, plus .gitignore additions (node_modules etc.).
3. Resolve WHICH behavior is genuinely cycle 1 and recommend it with rationale (weigh the walking-skeleton/happy-path argument vs the repo's repeated "NO_COVERAGE first" notes).
4. List risks.

Output strictly via the StructuredOutput schema. Proposal only — write nothing.`,
  { label: 'system-architect', phase: 'Design', schema: ARCH_SCHEMA, agentType: 'octo:droids:octo-backend-architect' },
)

const sdet = await agent(
  `You are the SENIOR SDET / TEST-AUTOMATION QA for this claims-adjudication take-home. You drive development test-first (red-green-refactor).
${READ}

The System Architect has just locked the contract and toolchain. Build your test to MATCH it exactly:
ARCHITECT OUTPUT (authoritative for signatures/naming/cycle-1):
${JSON.stringify(arch, null, 2)}

YOUR JOB:
1. Author the EXACT first failing test (complete, runnable file content) for the cycle-1 behavior the architect locked. Honor tdd-discipline/SKILL.md: BDD it() name, strict AAA, use builders, assert DOMAIN outcomes (payable/member/status/reasons) — NEVER HTTP status or return-type only. No "any", no shared mutable state, no spying on internals. Field names MUST match the architect's locked convention and signature.
2. Design app/tests/builders.ts with full code: aPolicy / aCoverageRule / aLineItem / anAccumulator (+ any helper to assemble the adjudicate input). Each returns a fully-valid object; tests override only what they assert on. Integer cents everywhere.
3. State exactly what RED looks like (the precise failure once the test runs against the empty scaffold — the RIGHT reason).
4. Give the commit sequence (test: ... then feat: ...).
5. Independently recommend cycle-1 (agree or push back on the architect).
6. List the test smells you deliberately avoided.

Output strictly via the StructuredOutput schema. Proposal only — write nothing, commit nothing.`,
  { label: 'senior-sdet-qa', phase: 'Design', schema: SDET_SCHEMA, agentType: 'octo:personas:test-automator' },
)

// ---------- Phase 2: Verify ----------
phase('Verify')

const verdict = await agent(
  `You are an ADVERSARIAL REVIEWER (staff engineer) gatekeeping the first TDD cycle of a graded take-home. Your default is skepticism: find what's wrong before approving.
${READ}

Review BOTH proposals against the locked rules (AGENTS.md hard rules + anti-patterns, tdd-discipline MUST/MUST-NOT, insurance-domain canonical order, integer-cents, PRD scope):

ARCHITECT:
${JSON.stringify(arch, null, 2)}

SDET:
${JSON.stringify(sdet, null, 2)}

Decide:
- Is the proposed first test a TRUE red-step that fails for the RIGHT reason on the current empty scaffold? Will the toolchain actually let "pnpm test" run (deps complete, vitest config valid, TS strict, ESM/paths sane)?
- Does the test assert domain behavior (amounts/status/reasons), not HTTP/types? Any "any", shared state, internal spying, float money, or speculative scope creep?
- Reconcile the cycle-1 conflict and the naming/signature conflict into ONE final pick each, with reasons.
- Is the contract the first test pins consistent with adjudication-plan.md's adjudicateLine and the invariant payable + member == billed?
- List any blocking issues and concrete adjustments before code is written.

Output strictly via the StructuredOutput schema.`,
  { label: 'adversarial-reviewer', phase: 'Verify', schema: VERDICT_SCHEMA, agentType: 'octo:droids:octo-code-reviewer' },
)

return { arch, sdet, verdict }

